sub_queries.sql:
SELECT Nationality, COUNT(*) AS count
FROM T24
GROUP BY Nationality;

SELECT Country, Team, Points
FROM T83
WHERE Points = (SELECT MAX(Points) FROM T83);

SELECT * 
FROM T83 
WHERE LOWER(Country) LIKE LOWER('%england%') OR LOWER(Country) LIKE LOWER('%france%') OR LOWER(Country) LIKE LOWER('%spain%');

SELECT MIN(Round) AS Min_Round, MAX(Round) AS Max_Round
FROM (
    SELECT Round FROM T93
    UNION ALL
    SELECT Round FROM T94
);

SELECT MIN(Pick) AS Min_Pick, MAX(Pick) AS Max_Pick
FROM (
    SELECT Pick FROM T93
    UNION ALL
    SELECT Pick FROM T94
);

SELECT DISTINCT College FROM T93
UNION
SELECT DISTINCT College FROM T94;

SELECT International_market, Film, Studio, Revenue, Admissions, Production_country
FROM T8
WHERE CAST(REPLACE(REPLACE(REPLACE(Revenue, '$', ''), ',', ''), ' ', '') AS REAL) > 0 OR CAST(REPLACE(REPLACE(Admissions, ',', ''), ' ', '') AS REAL) > 0;

SELECT Location 
FROM T34 
WHERE Time = (SELECT MIN(CAST(Time AS REAL)) FROM T34);

SELECT Player, Position 
FROM T17 
WHERE col_2010_Team IS NOT NULL AND col_2011_Team IS NOT NULL;

SELECT Year, Time, Athlete, Location
FROM T34
ORDER BY Year ASC;

SELECT School 
FROM T87 
WHERE Number LIKE '9/9';
